  ('aboriginal-c5fb3965-moex-00279', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '關於死亡宣告之登記，下列敘述何者錯誤？', '["法院應將死亡宣告裁判確定證明書送當事人戶籍地直轄市、縣（市）主管機關", "戶政事務所應催告死亡宣告之聲請人申請死亡登記", "戶政事務所應逕為死亡宣告登記", "如死亡宣告經法院裁定撤銷，戶政事務所應經催告後逕行辦理撤銷死亡宣告登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00280', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '關於無依兒童姓名之決定，下列敘述何者正確？', '["依母姓登記", "依父姓登記", "以抽籤決定依父姓或母姓登記", "依監護人之姓登記，並由戶政事務所主任代立名字"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00281', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '甲終止與其養子乙之收養關係，關於終止收養登記，下列敘述何者正確？', '["應以甲為申請人，甲不為申請時，以乙為申請人", "甲得以書面委託他人申請，無須戶政事務所核准", "如經戶政事務所催告仍無人申請時，戶政事務所仍不得為登記", "戶政事務所查驗終止收養登記之證明文件後，須留存文件之正本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00282', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '下列何者，不屬於死亡登記之申請人？', '["配偶", "戶長", "受僱人", "經理殮葬之人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00283', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '甲乙結婚後，發生甲是否重婚致結婚無效之爭議。關於甲乙結婚之戶籍登記，下列敘述何者正確？', '["因結婚無效，結婚之戶籍登記亦應為無效", "因嗣後發現重婚事由，戶政事務所應為結婚登記之廢止登記", "因甲乙結婚是否無效有爭議，戶政事務所應於戶籍登記中另為註記", "戶政事務所應於判決確定後，依當事人申請為結婚登記之撤銷登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00284', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '申請人申請戶籍登記之證明文件為外文，下列敘述何者正確？', '["該文件於國外作成者，應經駐外館處驗證，並檢附該文件正本", "該文件於澳門作成者，應經行政院設立或指定之機構或委託之民間團體驗證，並檢附該文件正本", "該文件於香港作成者，應經內政部驗證，並檢附經駐外館處驗證之中文譯本", "該文件於國內由外國駐我國使領館作成者，應經外交部驗證，並檢附經國內公證人認證之中文譯本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
